Identifiquei exatamente o problema.

**O Diagnóstico:**
1.  **O "Telefone sem Fio":** O Código do Backend (Google Sheets) lê as colunas e transforma tudo em letras minúsculas (ex: `currentbalance`) para evitar erros de digitação.
2.  **O Erro:** O Site (Frontend) está esperando as letras maiúsculas no meio (CamelCase, ex: `currentBalance`).
3.  **O Resultado:** O site procura `currentBalance`, não acha (porque veio `currentbalance`), assume que é zero, e a tela de Distribuição esconde produtos com saldo zero.

**A Solução:**
Vou ajustar o `inventoryService.ts` para ser um "tradutor" inteligente. Ele vai entender que `currentbalance`, `CurrentBalance` ou `Saldo Atual` significam a mesma coisa.

Também vou atualizar o Backend (`Settings.tsx`) para garantir que a baixa de estoque (distribuição) procure a coluna correta pelo nome, e não por uma posição fixa, evitando erros se você mudou a ordem das colunas na planilha.

### O que você precisa fazer:

1.  **Baixe/Atualize** o código abaixo no seu computador.
2.  **Atualize o Backend (Obrigatório):**
    *   Vá em **Configurações > Atualizar Backend**.
    *   Copie o código.
    *   No Google Sheets > Extensões > Apps Script.
    *   Cole e **Implantar > Gerenciar > Editar > Nova Versão > Implantar**.

Aqui estão as correções:

# Updated files:

## services/inventoryService.ts

Implementação de um mapeador de dados inteligente (`mapBackendToProduct`) dentro do `processData`. Ele traduz as chaves minúsculas vindas do Google Sheets (ex: 'currentbalance', 'neid') para o formato correto que o sistema espera (ex: 'currentBalance', 'neId'), resolvendo o problema de estoque zerado/invisível.

## pages/Settings.tsx

Atualização do Backend (v3.2) para tornar a função `distribute` (baixa de estoque) dinâmica. Agora ela procura a coluna 'currentBalance' pelo nome no cabeçalho, em vez de usar um índice fixo (coluna 8), evitando erros graves se a planilha for alterada.

```tsx
import React, { useEffect, useState } from 'react';
import { inventoryService } from '../services/inventoryService';
import { User, UserRole } from '../types';
import { Users, UserPlus, Shield, Edit, Trash2, Check, X, HelpCircle, Database, Save, Copy, Key, Lock, ShieldAlert, RefreshCw, Eye, EyeOff } from 'lucide-react';

const BACKEND_CODE = `
// ==================================================
// CÓDIGO DO BACKEND (Google Apps Script)
// VERSÃO: BLINDADA 3.2 (Correção Estoque e Baixa)
// ==================================================

function doGet(e) { return handleRequest(e); }
function doPost(e) { return handleRequest(e); }

function handleRequest(e) {
  const lock = LockService.getScriptLock();
  lock.tryLock(30000);

  try {
    const action = e.parameter.action;
    const ss = SpreadsheetApp.getActiveSpreadsheet();

    // Payload Parse
    let payload = null;
    try {
      if (e.postData && e.postData.contents) {
        const json = JSON.parse(e.postData.contents);
        if (!action && json.action) {
           const act = json.action;
           const pld = json.payload;
           if (act === 'saveUser') return saveUser(ss, pld);
           if (act === 'changePassword') return changePassword(ss, pld);
           if (act === 'createNE') return createNE(ss, pld);
           if (act === 'distribute') return distribute(ss, pld);
           if (act === 'reverse') return reverseMovement(ss, pld);
           if (act === 'saveCatalog') return saveCatalog(ss, pld);
           if (act === 'deleteCatalog') return deleteCatalog(ss, pld);
        }
        payload = json.payload;
      }
    } catch (err) {}

    if (action === 'getAll') return createJSONOutput(getAllData(ss));
    if (action === 'saveUser') return saveUser(ss, payload);
    if (action === 'changePassword') return changePassword(ss, payload);
    if (action === 'createNE') return createNE(ss, payload);
    if (action === 'distribute') return distribute(ss, payload);
    if (action === 'reverse') return reverseMovement(ss, payload);
    if (action === 'saveCatalog') return saveCatalog(ss, payload);
    if (action === 'deleteCatalog') return deleteCatalog(ss, payload);

    return createJSONOutput({ error: 'Ação desconhecida: ' + action });

  } catch (e) {
    return createJSONOutput({ error: e.toString() });
  } finally {
    lock.releaseLock();
  }
}

function createJSONOutput(data) {
  return ContentService.createTextOutput(JSON.stringify(data))
    .setMimeType(ContentService.MimeType.JSON);
}

function normalizeKey(key) {
  return String(key).toLowerCase().trim().replace(/\\s/g, '');
}

function getAllData(ss) {
  checkAndFixHeaders(ss);

  return {
    users: sheetToJSON(getOrCreateSheet(ss, 'Users')),
    products: sheetToJSON(getOrCreateSheet(ss, 'Products')),
    movements: sheetToJSON(getOrCreateSheet(ss, 'Movements')),
    nes: sheetToJSON(getOrCreateSheet(ss, 'NotaEmpenho')),
    catalog: sheetToJSON(getOrCreateSheet(ss, 'Catalog'))
  };
}

function changePassword(ss, payload) {
  const sheet = getOrCreateSheet(ss, 'Users');
  const data = sheet.getDataRange().getValues();
  const headers = data[0];

  let passColIndex = -1;
  let emailColIndex = -1;

  for (let i = 0; i < headers.length; i++) {
    const h = normalizeKey(headers[i]);
    if (h.includes('password') || h === 'senha') passColIndex = i;
    if (h.includes('email')) emailColIndex = i;
  }

  if (passColIndex === -1 || emailColIndex === -1) {
    return createJSONOutput({ success: false, error: 'Colunas Email/Senha não encontradas.' });
  }

  const targetEmail = normalizeKey(payload.email);

  for (let i = 1; i < data.length; i++) {
    if (normalizeKey(data[i][emailColIndex]) === targetEmail) {
      sheet.getRange(i + 1, passColIndex + 1).setValue(payload.password);
      return createJSONOutput({ success: true });
    }
  }

  return createJSONOutput({ success: false, error: 'Usuário não encontrado.' });
}

function saveUser(ss, user) {
  const sheet = getOrCreateSheet(ss, 'Users');
  const headers = sheet.getRange(1, 1, 1, sheet.getLastColumn()).getValues()[0];

  const colMap = {};
  headers.forEach((h, i) => { colMap[normalizeKey(h)] = i + 1; });

  if (!colMap['password']) {
    const newCol = headers.length + 1;
    sheet.getRange(1, newCol).setValue('password');
    colMap['password'] = newCol;
  }

  const data = sheet.getDataRange().getValues();
  let rowIndex = -1;
  const targetEmail = normalizeKey(user.email);
  const emailColIdx = colMap['email'] ? colMap['email'] - 1 : 0;

  for (let i = 1; i < data.length; i++) {
    if (normalizeKey(data[i][emailColIdx]) === targetEmail) {
      rowIndex = i + 1;
      break;
    }
  }

  let passwordToSave = user.password;
  if (rowIndex > 0 && (!passwordToSave || passwordToSave === '')) {
     const passColIdx = colMap['password'] - 1;
     if (passColIdx >= 0) {
        passwordToSave = data[rowIndex-1][passColIdx]; 
     }
  }
  if (!passwordToSave) passwordToSave = '';

  if (rowIndex > 0) {
    if (colMap['name']) sheet.getRange(rowIndex, colMap['name']).setValue(user.name);
    if (colMap['role']) sheet.getRange(rowIndex, colMap['role']).setValue(user.role);
    if (colMap['active']) sheet.getRange(rowIndex, colMap['active']).setValue(user.active);
    sheet.getRange(rowIndex, colMap['password']).setValue(passwordToSave);
  } else {
    const newRow = [];
    headers.forEach(h => {
        const key = normalizeKey(h);
        if (key === 'email') newRow.push(user.email);
        else if (key === 'name') newRow.push(user.name);
        else if (key === 'role') newRow.push(user.role);
        else if (key === 'active') newRow.push(user.active);
        else if (key === 'password') newRow.push(passwordToSave);
        else newRow.push('');
    });
    if (!colMap['password'] && headers.length < Object.keys(colMap).length) { newRow.push(passwordToSave); }
    if (newRow.length === 0) { sheet.appendRow([user.email, user.name, user.role, user.active, passwordToSave]); } 
    else { sheet.appendRow(newRow); }
  }
  return createJSONOutput({ success: true });
}

function saveCatalog(ss, item) {
  const sheet = getOrCreateSheet(ss, 'Catalog');
  const data = sheet.getDataRange().getValues();
  const targetName = normalizeKey(item.name);
  let rowIndex = -1;
  for (let i = 1; i < data.length; i++) {
    if (normalizeKey(data[i][0]) === targetName) { rowIndex = i + 1; break; }
  }
  const rowData = [item.name, item.unit, item.category || 'Geral'];
  if (rowIndex > 0) { sheet.getRange(rowIndex, 1, 1, 3).setValues([rowData]); } 
  else { sheet.appendRow(rowData); }
  return createJSONOutput({ success: true });
}

function deleteCatalog(ss, item) {
  const sheet = getOrCreateSheet(ss, 'Catalog');
  const data = sheet.getDataRange().getValues();
  const targetName = normalizeKey(item.name);
  for (let i = 1; i < data.length; i++) {
    if (normalizeKey(data[i][0]) === targetName) { sheet.deleteRow(i + 1); return createJSONOutput({ success: true }); }
  }
  return createJSONOutput({ success: false, error: 'Item não encontrado' });
}

function createNE(ss, payload) {
  const neSheet = getOrCreateSheet(ss, 'NotaEmpenho');
  const prodSheet = getOrCreateSheet(ss, 'Products');
  const movSheet = getOrCreateSheet(ss, 'Movements');
  neSheet.appendRow([payload.ne.id, payload.ne.supplier, payload.ne.date, payload.ne.status, payload.ne.totalValue]);
  const products = payload.items;
  const prodRows = products.map(p => [p.id, p.neId, p.name, p.unit, p.qtyPerPackage, p.initialQty, p.unitValue, p.currentBalance, p.minStock, p.createdAt]);
  if (prodRows.length > 0) prodSheet.getRange(prodSheet.getLastRow() + 1, 1, prodRows.length, prodRows[0].length).setValues(prodRows);
  const movements = payload.movements;
  const movRows = movements.map(m => [m.id, m.date, m.type, m.neId, m.productId, m.productName, m.quantity, m.value, m.userEmail, m.observation, m.isReversed || false]);
  if (movRows.length > 0) movSheet.getRange(movSheet.getLastRow() + 1, 1, movRows.length, movRows[0].length).setValues(movRows);
  return createJSONOutput({ success: true });
}

function distribute(ss, payload) {
  const prodSheet = getOrCreateSheet(ss, 'Products');
  const movSheet = getOrCreateSheet(ss, 'Movements');

  // Mapeamento dinâmico de colunas para Produtos
  const prodHeaders = prodSheet.getRange(1, 1, 1, prodSheet.getLastColumn()).getValues()[0];
  let idCol = -1, balCol = -1;
  prodHeaders.forEach((h, i) => {
      const nh = normalizeKey(h);
      if (nh === 'id') idCol = i;
      if (nh === 'currentbalance' || nh === 'saldoatual') balCol = i;
  });

  if (idCol === -1 || balCol === -1) return createJSONOutput({ success: false, error: 'Colunas de Produto incorretas.' });

  const movements = payload.movements;
  const movRows = movements.map(m => [m.id, m.date, m.type, m.neId, m.productId, m.productName, m.quantity, m.value, m.userEmail, m.observation, false]);
  movSheet.getRange(movSheet.getLastRow() + 1, 1, movRows.length, movRows[0].length).setValues(movRows);

  const prodData = prodSheet.getDataRange().getValues();
  const prodMap = new Map();
  // Começa do 1 (pula header)
  for (let i = 1; i < prodData.length; i++) {
      prodMap.set(String(prodData[i][idCol]), i + 1); // Guarda o número da linha
  }

  movements.forEach(m => {
    const row = prodMap.get(String(m.productId));
    if (row) {
      const currentBalance = prodSheet.getRange(row, balCol + 1).getValue();
      prodSheet.getRange(row, balCol + 1).setValue(Number(currentBalance) - Number(m.quantity));
    }
  });

  const scriptProperties = PropertiesService.getScriptProperties();
  let lastId = Number(scriptProperties.getProperty('LAST_REC_ID')) || 0;
  lastId++;
  scriptProperties.setProperty('LAST_REC_ID', lastId.toString());
  const year = new Date().getFullYear();
  const receiptId = "REC-" + ("0000" + lastId).slice(-4) + "/" + year;
  return createJSONOutput({ success: true, receiptId: receiptId });
}

function reverseMovement(ss, payload) {
  const movSheet = getOrCreateSheet(ss, 'Movements');
  const prodSheet = getOrCreateSheet(ss, 'Products');

  // Mapas dinâmicos
  const prodHeaders = prodSheet.getRange(1, 1, 1, prodSheet.getLastColumn()).getValues()[0];
  let pIdCol = -1, pBalCol = -1;
  prodHeaders.forEach((h, i) => {
      if (normalizeKey(h) === 'id') pIdCol = i;
      if (normalizeKey(h) === 'currentbalance') pBalCol = i;
  });

  const originalId = payload.movementId;
  const reversal = payload.reversalMovement;
  const movData = movSheet.getDataRange().getValues();

  // Achar mov original para marcar
  for (let i = 1; i < movData.length; i++) {
    if (movData[i][0] === originalId) { 
        // Assume isReversed está na coluna 11 (K). Melhor seria dinâmico também, mas mantendo simples por ora.
        movSheet.getRange(i + 1, 11).setValue(true); 
        break; 
    }
  }

  const m = reversal;
  movSheet.appendRow([m.id, m.date, m.type, m.neId, m.productId, m.productName, m.quantity, m.value, m.userEmail, m.observation, false]);

  // Devolver Saldo
  if (pIdCol !== -1 && pBalCol !== -1) {
      const prodData = prodSheet.getDataRange().getValues();
      for (let i = 1; i < prodData.length; i++) {
        if (String(prodData[i][pIdCol]) === String(m.productId)) {
          const currentBalance = prodSheet.getRange(i + 1, pBalCol + 1).getValue();
          prodSheet.getRange(i + 1, pBalCol + 1).setValue(Number(currentBalance) + Number(m.quantity));
          break;
        }
      }
  }
  return createJSONOutput({ success: true });
}

function getOrCreateSheet(ss, name) {
  let sheet = ss.getSheetByName(name);
  if (!sheet) {
    sheet = ss.insertSheet(name);
    if (name === 'Users') sheet.appendRow(['email', 'name', 'role', 'active', 'password']);
    if (name === 'Products') sheet.appendRow(['id', 'neId', 'name', 'unit', 'qtyPerPackage', 'initialQty', 'unitValue', 'currentBalance', 'minStock', 'createdAt']);
    if (name === 'Movements') sheet.appendRow(['id', 'date', 'type', 'neId', 'productId', 'productName', 'quantity', 'value', 'userEmail', 'observation', 'isReversed']);
    if (name === 'NotaEmpenho') sheet.appendRow(['id', 'supplier', 'date', 'status', 'totalValue']);
    if (name === 'Catalog') sheet.appendRow(['name', 'unit', 'category']);
  }
  return sheet;
}

function checkAndFixHeaders(ss) {
  const userSheet = ss.getSheetByName('Users');
  if (userSheet && userSheet.getLastColumn() > 0) {
    const headers = userSheet.getRange(1, 1, 1, userSheet.getLastColumn()).getValues()[0];
    const hasPassword = headers.some(h => normalizeKey(h).includes('password'));
    if (!hasPassword) { userSheet.getRange(1, headers.length + 1).setValue('password'); }
  }
}

function sheetToJSON(sheet) {
  const data = sheet.getDataRange().getValues();
  if (data.length === 0) return [];
  const headers = data[0];
  const result = [];
  for (let i = 1; i < data.length; i++) {
    const row = data[i];
    const obj = {};
    for (let j = 0; j < headers.length; j++) {
      const key = normalizeKey(headers[j]);
      obj[key] = row[j];
    }
    result.push(obj);
  }
  return result;
}
