-- SQL script to create tables and RLS policies

-- Users Table
create table users (
    id uuid default uuid_generate_v4() primary key,
    username text not null unique,
    password text not null, -- Storing encrypted password here
    created_at timestamp with time zone default now()
);
alter table users enable row level security;
create policy "Users: public read" on users for select using (true);
create policy "Users: authenticated read & write" on users for all using (auth.role() = 'authenticated');

