import { Product, NotaEmpenho, Movement, MovementType, DashboardStats, NEStatus, User, UserRole, CatalogItem } from '../types';
import { supabase } from './supabaseClient';

class InventoryService {
  private listeners: (() => void)[] = [];
  private cachedUser: User | null = null;

  constructor() {}

  public subscribe(listener: () => void): () => void {
    this.listeners.push(listener);
    return () => { this.listeners = this.listeners.filter(l => l !== listener); };
  }

  private notifyListeners() { this.listeners.forEach(l => l()); }

  async testConnection() {
    try {
      const { data, error } = await supabase.from('users').select('count', { count: 'exact', head: true });
      if (error) throw error;
      return { success: true, message: "Conectado ao Banco de Dados SQL (Supabase)!" };
    } catch (e: any) {
      console.error(e);
      return { success: false, message: `Erro de conexão: ${e.message}. Verifique o arquivo supabaseClient.ts` };
    }
  }

  async hashPassword(password: string): Promise<string> {
    const encoder = new TextEncoder();
    const salt = encoder.encode("DTIC_ALMOXARIFADO_SECURE_SALT_2026");
    const keyMaterial = await crypto.subtle.importKey("raw", encoder.encode(password), { name: "PBKDF2" }, false, ["deriveBits", "deriveKey"]);
    const key = await crypto.subtle.deriveKey({ name: "PBKDF2", salt: salt, iterations: 100000, hash: "SHA-256" }, keyMaterial, { name: "AES-GCM", length: 256 }, true, ["encrypt", "decrypt"]);
    const exported = await crypto.subtle.exportKey("raw", key);
    return Array.from(new Uint8Array(exported)).map(b => b.toString(16).padStart(2, '0')).join('');
  }

  async getCurrentUser(): Promise<User> {
    const storedEmail = localStorage.getItem('almoxarifado_user');
    if (!storedEmail) return { email: 'public@guest.com', name: 'Visitante', role: UserRole.GUEST, active: true };
    if (storedEmail === 'admin@resgate') return { email: 'admin@resgate', name: 'Admin Resgate', role: UserRole.ADMIN, active: true };
    if (this.cachedUser && this.cachedUser.email === storedEmail) return this.cachedUser;

    const { data } = await supabase.from('users').select('*').ilike('email', storedEmail).eq('active', true).maybeSingle();
    if (data) {
      this.cachedUser = { email: data.email, name: data.name, role: data.role as UserRole, active: data.active, password: data.password };
      return this.cachedUser;
    }
    return { email: 'public@guest.com', name: 'Visitante', role: UserRole.GUEST, active: true };
  }

  async login(email: string, password: string) {
    const normalizedEmail = email.toLowerCase().trim();
    if (!password || password.trim() === '') return false;
    const { data: user } = await supabase.from('users').select('*').ilike('email', normalizedEmail).eq('active', true).maybeSingle();
    if (user) {
      const storedPass = (user.password || '').trim();
      if (storedPass.length === 64 && /^[0-9a-fA-F]+$/.test(storedPass)) {
          const inputHash = await this.hashPassword(password.trim());
          if (storedPass === inputHash) { this.setCurrentUser(user); return true; }
      } else if (storedPass === password.trim()) {
          const newHash = await this.hashPassword(password.trim());
          await supabase.from('users').update({ password: newHash }).eq('id', user.id);
          this.setCurrentUser(user); return true;
      }
      return false;
    }
    const { count } = await supabase.from('users').select('*', { count: 'exact', head: true });
    if ((count === 0 || count === null) && (normalizedEmail === 'admin' || normalizedEmail === 'admin@resgate')) {
       if (password === 'admin') {
         this.setCurrentUser({ email: 'admin@resgate', name: 'Admin Resgate', role: UserRole.ADMIN, active: true });
         return true;
       }
    }
    return false;
  }

  async logout() { localStorage.removeItem('almoxarifado_user'); this.cachedUser = null; this.notifyListeners(); }
  private setCurrentUser(user: any) { localStorage.setItem('almoxarifado_user', user.email); this.cachedUser = user; this.notifyListeners(); }

  async getUsers() {
    const { data } = await supabase.from('users').select('*').order('name');
    return (data || []).map((u: any) => ({ ...u, role: u.role as UserRole }));
  }

  async saveUser(user: User) {
    const { data: existing } = await supabase.from('users').select('id').ilike('email', user.email).maybeSingle();
    const payload: any = { email: user.email.toLowerCase(), name: user.name, role: user.role, active: user.active };
    if (user.password) payload.password = user.password;
    let error = null;
    if (existing) { const result = await supabase.from('users').update(payload).eq('id', existing.id); error = result.error; }
    else { const result = await supabase.from('users').insert([payload]); error = result.error; }
    return { success: !error, error: error?.message };
  }

  async changeOwnPassword(oldP: string, newP: string) {
    const currentUser = await this.getCurrentUser();
    const { data: userInDb } = await supabase.from('users').select('*').ilike('email', currentUser.email).single();
    if (!userInDb) return { success: false, message: 'Usuário não encontrado.' };
    const storedPass = (userInDb.password || '').trim();
    let isOldCorrect = false;
    if (storedPass.length === 64) { const oldH = await this.hashPassword(oldP.trim()); isOldCorrect = (oldH === storedPass); }
    else { isOldCorrect = (storedPass === oldP.trim()); }
    if (!isOldCorrect) return { success: false, message: 'Senha atual incorreta.' };
    const newHash = await this.hashPassword(newP);
    const { error } = await supabase.from('users').update({ password: newHash }).eq('id', userInDb.id);
    return { success: !error, message: error ? error.message : 'Sucesso' };
  }

  async getCatalog() { const { data } = await supabase.from('catalog').select('*').order('name'); return data || []; }
  async saveCatalogItem(item: CatalogItem) {
    const { data: existing } = await supabase.from('catalog').select('id').ilike('name', item.name).maybeSingle();
    if (existing) { const { error } = await supabase.from('catalog').update(item).eq('id', existing.id); return !error; }
    else { const { error } = await supabase.from('catalog').insert([item]); return !error; }
  }
  async deleteCatalogItem(item: CatalogItem) { const { error } = await supabase.from('catalog').delete().ilike('name', item.name); return !error; }

  async getProducts() {
    const { data } = await supabase.from('products').select('*');
    return (data || []).map((p: any) => ({ id: p.id, neId: p.ne_id, name: p.name, unit: p.unit, qtyPerPackage: p.qty_per_package, initialQty: p.initial_qty, unitValue: p.unit_value, currentBalance: p.current_balance, minStock: p.min_stock, createdAt: p.created_at }));
  }

  async getConsolidatedStock() {
    const products = await this.getProducts();
    const map = new Map();
    products.forEach(p => {
      const nameKey = p.name.trim(); 
      if (!map.has(nameKey)) { map.set(nameKey, { name: p.name, totalBalance: 0, unit: p.unit }); }
      const item = map.get(nameKey)!;
      item.totalBalance += p.currentBalance;
    });
    return Array.from(map.values()).filter((item: any) => item.totalBalance > 0);
  }

  async getNotaEmpenho(id: string) {
    const { data, error } = await supabase.from('nota_empenho').select('*').eq('id', id).maybeSingle();
    return data;
  }

  async createNotaEmpenho(ne: any, items: any[]) {
    // 1. Verifica se a NE já existe
    const { data: existingNE } = await supabase.from('nota_empenho').select('id, total_value').eq('id', ne.number).maybeSingle();

    const itemsTotalValue = items.reduce((a, i) => a + (i.initialQty * i.unitValue), 0);

    if (existingNE) {
      // Se existe, apenas atualiza o valor total acumulado da NE
      const newTotal = Number(existingNE.total_value) + itemsTotalValue;
      const { error: updateError } = await supabase.from('nota_empenho').update({ total_value: newTotal }).eq('id', ne.number);
      if (updateError) { console.error("Erro ao atualizar NE existente", updateError); return false; }
    } else {
      // Se não existe, cria a NE normalmente
      const { error: neError } = await supabase.from('nota_empenho').insert([{
        id: ne.number,
        supplier: ne.supplier,
        date: ne.date,
        status: NEStatus.OPEN,
        total_value: itemsTotalValue
      }]);
      if (neError) { console.error("Erro ao criar nova NE", neError); return false; }
    }

    const user = await this.getCurrentUser();
    const ts = new Date().toISOString();
    const productsPayload = [];
    const movementsPayload = [];

    items.forEach((i, idx) => {
      const pid = `P-${Date.now()}-${idx}`;
      productsPayload.push({ id: pid, ne_id: ne.number, name: i.name, unit: i.unit, qty_per_package: i.qtyPerPackage, initial_qty: i.initialQty, unit_value: i.unitValue, current_balance: i.initialQty, min_stock: i.minStock, created_at: ts });
      movementsPayload.push({ id: `MOV-IN-${Date.now()}-${idx}`, date: ts, type: MovementType.ENTRY, ne_id: ne.number, product_id: pid, product_name: i.name, quantity: i.initialQty, value: i.initialQty * i.unitValue, user_email: user.email, observation: 'Entrada Inicial', is_reversed: false });
    });

    const { error: prodError } = await supabase.from('products').insert(productsPayload);
    if (prodError) return false;

    const { error: movError } = await supabase.from('movements').insert(movementsPayload);
    if (movError) return false;

    this.notifyListeners();
    return true;
  }

  async calculateDistribution(name: string, qty: number) {
    const { data: batches } = await supabase.from('products').select('*').ilike('name', name).gt('current_balance', 0).order('created_at', { ascending: true });
    if (!batches) return { itemsToDeduct: [], remainingQty: qty };
    let qtyNeeded = qty;
    const items = [];
    for (const b of batches) {
      if (qtyNeeded <= 0) break;
      const take = Math.min(b.current_balance, qtyNeeded);
      items.push({ productId: b.id, neId: b.ne_id, qty: take, unitValue: b.unit_value });
      qtyNeeded -= take;
    }
    return { itemsToDeduct: items, remainingQty: qtyNeeded };
  }

  async executeDistribution(movementsAllocated: any[], userEmail: string, obs: string) {
    const timestamp = new Date().toISOString();
    const movementsPayload = [];
    const { count } = await supabase.from('movements').select('*', { count: 'exact', head: true });
    const seq = (count || 0) + 1;
    const year = new Date().getFullYear();
    const receiptId = `REC-${String(seq).padStart(4, '0')}/${year}`;

    for (const m of movementsAllocated) {
      const { data: prod } = await supabase.from('products').select('name').eq('id', m.productId).single();
      movementsPayload.push({ id: `MOV-OUT-${Date.now()}-${Math.floor(Math.random()*1000)}`, date: timestamp, type: MovementType.EXIT, ne_id: m.neId, product_id: m.productId, product_name: prod?.name || 'Unknown', quantity: m.qty, value: m.qty * m.unitValue, user_email: userEmail, observation: obs, is_reversed: false });
      const { data: currentP } = await supabase.from('products').select('current_balance').eq('id', m.productId).single();
      if (currentP) await supabase.from('products').update({ current_balance: Number(currentP.current_balance) - Number(m.qty) }).eq('id', m.productId);
    }
    const { error } = await supabase.from('movements').insert(movementsPayload);
    if (!error) { this.notifyListeners(); return { success: true, receiptId }; }
    return { success: false };
  }

  async getMovements() {
    const { data } = await supabase.from('movements').select('*').order('date', { ascending: false });
    return (data || []).map((m: any) => ({ id: m.id, date: m.date, type: m.type as MovementType, neId: m.ne_id, productId: m.product_id, productName: m.product_name, quantity: m.quantity, value: m.value, userEmail: m.user_email, observation: m.observation, isReversed: m.is_reversed }));
  }

  async reverseMovement(id: string, email: string) {
    const { data: original } = await supabase.from('movements').select('*').eq('id', id).single();
    if (!original) return false;
    await supabase.from('movements').update({ is_reversed: true }).eq('id', id);
    const reversal = { ...original, id: `REV-${Date.now()}`, type: MovementType.REVERSAL, user_email: email, observation: `Estorno de ${original.id}`, is_reversed: false, date: new Date().toISOString() };
    delete reversal.created_at; 
    await supabase.from('movements').insert([reversal]);
    const { data: prod } = await supabase.from('products').select('current_balance').eq('id', original.product_id).single();
    if (prod) await supabase.from('products').update({ current_balance: prod.current_balance + original.quantity }).eq('id', original.product_id);
    this.notifyListeners(); return true;
  }

  async getDashboardStats(): Promise<DashboardStats> {
    const { data: products } = await supabase.from('products').select('current_balance, unit_value, name, min_stock, unit');
    const { data: movements } = await supabase.from('movements').select('value, date, type, is_reversed, quantity, product_name');
    const totalValueStock = (products || []).reduce((acc, p) => acc + (p.current_balance * p.unit_value), 0);
    const lowStockCount = (products || []).filter(p => p.current_balance <= p.min_stock).length;
    const criticalItems = (products || []).filter(p => p.current_balance <= p.min_stock && p.current_balance >= 0).sort((a,b) => a.current_balance - b.current_balance).slice(0, 5).map(p => ({ name: p.name, balance: p.current_balance, min: p.min_stock, unit: p.unit }));
    const now = new Date();
    const currentMonthOutflow = (movements || []).filter(m => m.type === MovementType.EXIT && !m.is_reversed && new Date(m.date).getMonth() === now.getMonth() && new Date(m.date).getFullYear() === now.getFullYear()).reduce((acc, m) => acc + m.value, 0);
    const consumptionMap = new Map<string, number>();
    (movements || []).forEach(m => { if (m.type === MovementType.EXIT && !m.is_reversed) { const current = consumptionMap.get(m.product_name) || 0; consumptionMap.set(m.product_name, current + m.quantity); } });
    const topProducts = Array.from(consumptionMap.entries()).map(([name, value]) => ({ name, value })).sort((a, b) => b.value - a.value).slice(0, 5);
    return { totalValueStock, totalItems: (products || []).length, lowStockCount, monthlyOutflow: [], topProducts, currentMonthOutflow, criticalItems };
  }

  getApiUrl() { return 'SUPABASE_CONNECTED'; }
  public networkErrorStatus = { isError: false, type: null };
  async refreshData() { this.notifyListeners(); }
}

export const inventoryService = new InventoryService();

import { useState, useEffect } from 'react';
import { inventoryService } from '../services/inventoryService';
import { Plus, Trash2, Save, PackagePlus, CheckCircle, Info, Lock, ShieldAlert, Search, AlertCircle, Loader2 } from 'lucide-react';
import { User, UserRole, CatalogItem } from '../types';

interface NewItem {
  name: string;
  unit: string;
  qtyPerPackage: number;
  initialQty: number;
  unitValue: number;
  minStock: number;
}

const Entry: React.FC = () => {
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [pageLoading, setPageLoading] = useState(true);
  const [catalog, setCatalog] = useState<CatalogItem[]>([]);

  // NE State
  const [neNumber, setNeNumber] = useState('');
  const [supplier, setSupplier] = useState('');
  const [neDate, setNeDate] = useState(new Date().toISOString().split('T')[0]);
  const [existingNE, setExistingNE] = useState<any>(null);
  const [checkingNE, setCheckingNE] = useState(false);

  // Item Form State
  const [currentItem, setCurrentItem] = useState<NewItem>({
    name: '',
    unit: 'UN',
    qtyPerPackage: 1,
    initialQty: 0,
    unitValue: 0,
    minStock: 0
  });

  const [itemsList, setItemsList] = useState<NewItem[]>([]);
  const [loading, setLoading] = useState(false);
  const [successMsg, setSuccessMsg] = useState('');

  useEffect(() => {
    const load = async () => {
       try {
         const user = await inventoryService.getCurrentUser();
         setCurrentUser(user);
         const cat = await inventoryService.getCatalog();
         setCatalog(cat);
       } catch (e) {
         console.error(e);
       } finally {
         setPageLoading(false);
       }
    };
    load();
  }, []);

  // Verificar NE ao digitar
  useEffect(() => {
    const verifyNE = async () => {
      if (neNumber.length >= 3) {
        setCheckingNE(true);
        const data = await inventoryService.getNotaEmpenho(neNumber.toUpperCase());
        if (data) {
          setExistingNE(data);
          setSupplier(data.supplier);
          setNeDate(new Date(data.date).toISOString().split('T')[0]);
        } else {
          setExistingNE(null);
        }
        setCheckingNE(false);
      } else {
        setExistingNE(null);
      }
    };
    const timer = setTimeout(verifyNE, 500);
    return () => clearTimeout(timer);
  }, [neNumber]);

  const hasAccess = currentUser && (currentUser.role === UserRole.ADMIN || currentUser.role === UserRole.MANAGER);

  const handleProductSelect = (e: React.ChangeEvent<HTMLInputElement>) => {
    const val = e.target.value;
    const found = catalog.find(c => c.name === val);
    setCurrentItem(prev => ({
        ...prev,
        name: val,
        unit: found ? found.unit : prev.unit
    }));
  };

  const handleAddItem = () => {
    if (!currentItem.name || currentItem.initialQty <= 0 || currentItem.unitValue <= 0) return;
    setItemsList(prev => [...prev, currentItem]);
    setCurrentItem({
      name: '', unit: 'UN', qtyPerPackage: 1, initialQty: 0, unitValue: 0, minStock: 0
    });
  };

  const handleRemoveItem = (index: number) => {
    setItemsList(prev => prev.filter((_, i) => i !== index));
  };

  const handleSaveNE = async () => {
    if (!neNumber || !supplier || itemsList.length === 0 || !hasAccess) return;
    setLoading(true);
    try {
        const success = await inventoryService.createNotaEmpenho(
          { number: neNumber.toUpperCase(), supplier, date: neDate },
          itemsList
        );
        if (success) {
          setSuccessMsg(existingNE 
            ? `Itens adicionados à Nota de Empenho ${neNumber}!` 
            : `Nota de Empenho ${neNumber} cadastrada com sucesso!`);
          setNeNumber(''); setSupplier(''); setItemsList([]); setExistingNE(null);
          setTimeout(() => setSuccessMsg(''), 5000);
        } else {
          alert('Erro ao processar a gravação. Verifique se os dados estão corretos.');
        }
    } catch(e) { alert('Erro inesperado ao salvar.'); } 
    finally { setLoading(false); }
  };

  const totalValueNE = itemsList.reduce((acc, item) => acc + (item.initialQty * item.unitValue), 0);

  if (pageLoading) return <div className="p-8 text-center text-slate-500">Carregando...</div>;

  if (!hasAccess) {
    return (
      <div className="flex flex-col items-center justify-center min-h-[400px] text-center p-8">
        <div className="bg-red-50 p-6 rounded-full mb-4"><ShieldAlert className="w-16 h-16 text-red-600" /></div>
        <h2 className="text-2xl font-bold text-slate-800">Acesso Negado</h2>
        <p className="text-slate-500 mt-2 max-w-md">Seu perfil ({currentUser?.role}) não possui permissão para realizar Entradas.</p>
      </div>
    );
  }

  return (
    <div className="max-w-5xl mx-auto space-y-6">
      <div>
        <h2 className="text-3xl font-bold text-slate-800 flex items-center gap-3">
          <PackagePlus className="text-emerald-600" /> Entrada de Nota de Empenho
        </h2>
        <p className="text-slate-500 mt-2">Cadastro de NE e inclusão de novos materiais ao estoque.</p>
      </div>

      {successMsg && (
        <div className="bg-emerald-50 border border-emerald-200 text-emerald-700 p-4 rounded-lg flex items-center gap-3 animate-fade-in shadow-sm">
          <CheckCircle /> <span className="font-medium">{successMsg}</span>
        </div>
      )}

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
        <div className="lg:col-span-1 space-y-6">
          <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-200">
            <h3 className="font-bold text-lg mb-4 text-slate-700 border-b pb-2">Dados da NE</h3>
            <div className="space-y-4">
              <div>
                <label className="block text-sm font-medium text-slate-700 mb-1 flex justify-between">
                  Número da NE
                  {checkingNE && <Loader2 size={14} className="animate-spin text-sky-500" />}
                </label>
                <input type="text" className="w-full p-2.5 bg-slate-50 border border-slate-300 rounded-lg outline-none uppercase font-bold focus:ring-2 focus:ring-sky-500" value={neNumber} onChange={e => setNeNumber(e.target.value)} placeholder="Ex: 2026NE00123" />
                {existingNE && (
                  <div className="mt-2 text-xs bg-amber-50 text-amber-700 p-2 rounded border border-amber-200 flex items-center gap-2">
                    <AlertCircle size={14} /> <span>NE já cadastrada. Novos itens serão <strong>anexados</strong> a ela.</span>
                  </div>
                )}
              </div>
              <div>
                <label className="block text-sm font-medium text-slate-700 mb-1">Fornecedor</label>
                <input type="text" className={`w-full p-2.5 bg-slate-50 border border-slate-300 rounded-lg outline-none ${existingNE ? 'opacity-70 bg-slate-100 cursor-not-allowed' : ''}`} value={supplier} onChange={e => setSupplier(e.target.value)} disabled={!!existingNE} />
              </div>
              <div>
                <label className="block text-sm font-medium text-slate-700 mb-1">Data de Emissão</label>
                <input type="date" className={`w-full p-2.5 bg-slate-50 border border-slate-300 rounded-lg outline-none ${existingNE ? 'opacity-70 bg-slate-100 cursor-not-allowed' : ''}`} value={neDate} onChange={e => setNeDate(e.target.value)} disabled={!!existingNE} />
              </div>
            </div>
          </div>
          <div className={`p-6 rounded-xl shadow-lg transition-colors ${existingNE ? 'bg-amber-600' : 'bg-slate-800'} text-white`}>
            <p className="text-sm text-white/70 mb-1">Valor Total do Lote</p>
            <p className="text-3xl font-bold font-mono">R$ {totalValueNE.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}</p>
            <p className="text-xs text-white/70 mt-2">{itemsList.length} itens no lote atual</p>
            <button onClick={handleSaveNE} disabled={loading || !neNumber || itemsList.length === 0} className={`mt-6 w-full py-3 ${existingNE ? 'bg-white text-amber-700 hover:bg-amber-50' : 'bg-emerald-500 hover:bg-emerald-600 text-white'} font-bold rounded-lg flex justify-center items-center gap-2 disabled:opacity-50 disabled:cursor-not-allowed transition-all`}>
              {loading ? <Loader2 className="animate-spin" /> : <><Save size={18} /> {existingNE ? 'Anexar Itens' : 'Salvar e Confirmar'}</>}
            </button>
          </div>
        </div>

        <div className="lg:col-span-2 space-y-6">
          <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-200">
            <h3 className="font-bold text-lg mb-4 text-slate-700 flex items-center gap-2"><Plus size={20} className="text-emerald-600" /> Adicionar Item</h3>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-4 mb-4">
              <div className="md:col-span-2">
                <label className="block text-sm font-medium text-slate-700 mb-1">Descrição (Busque no Catálogo)</label>
                <input list="catalog-list" type="text" className="w-full p-2.5 bg-slate-50 border border-slate-300 rounded-lg outline-none focus:ring-2 focus:ring-accent" value={currentItem.name} onChange={handleProductSelect} placeholder="Digite para buscar..." />
                <datalist id="catalog-list">{catalog.map((c, i) => <option key={i} value={c.name} />)}</datalist>
              </div>
              <div>
                <label className="block text-sm font-medium text-slate-700 mb-1">Unidade</label>
                <select className="w-full p-2.5 bg-slate-50 border border-slate-300 rounded-lg outline-none bg-slate-50" value={currentItem.unit} onChange={e => setCurrentItem({...currentItem, unit: e.target.value})}>
                  <option value="UN">UN</option><option value="CX">CX</option><option value="PCT">PCT</option><option value="KG">KG</option><option value="L">L</option><option value="RESMA">RESMA</option>
                </select>
              </div>
              <div>
                <label className="block text-sm font-medium text-slate-700 mb-1">Qtd (Unidades)</label>
                <input type="number" className="w-full p-2.5 bg-slate-50 border border-slate-300 rounded-lg outline-none focus:ring-2 focus:ring-accent" value={currentItem.initialQty} onChange={e => { const qty = parseFloat(e.target.value) || 0; setCurrentItem({ ...currentItem, initialQty: qty, minStock: Math.ceil(qty * 0.10) }); }} />
              </div>
              <div>
                <label className="block text-sm font-medium text-slate-700 mb-1">Valor Unit. (R$)</label>
                <input type="number" className="w-full p-2.5 bg-slate-50 border border-slate-300 rounded-lg outline-none focus:ring-2 focus:ring-accent" value={currentItem.unitValue} onChange={e => setCurrentItem({...currentItem, unitValue: parseFloat(e.target.value) || 0})} />
              </div>
               <div>
                <label className="block text-sm font-medium text-slate-700 mb-1">Estoque Mín. (Sugestão 10%)</label>
                <input type="number" className="w-full p-2.5 bg-slate-50 border border-slate-300 rounded-lg outline-none text-slate-600" value={currentItem.minStock} onChange={e => setCurrentItem({...currentItem, minStock: parseFloat(e.target.value) || 0})} />
              </div>
            </div>
            <div className="flex justify-end">
              <button onClick={handleAddItem} disabled={!currentItem.name || currentItem.initialQty <= 0} className="px-6 py-2 bg-slate-800 text-white font-medium rounded-lg hover:bg-slate-700 disabled:opacity-50">Incluir Item no Lote</button>
            </div>
          </div>

          <div className="bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden">
            <div className="p-4 bg-slate-50 border-b border-slate-200 flex justify-between items-center">
               <h3 className="font-bold text-slate-700">Lote de Novos Itens</h3>
               <span className="text-sm bg-slate-200 px-2 py-1 rounded text-slate-600">{itemsList.length} itens prontos</span>
            </div>
            {itemsList.length > 0 ? (
              <table className="w-full text-sm text-left">
                <thead className="bg-slate-50 text-slate-500 font-medium border-b border-slate-200">
                  <tr><th className="p-3">Produto</th><th className="p-3 text-right">Qtd</th><th className="p-3 text-right">Total</th><th className="p-3 text-center">Ação</th></tr>
                </thead>
                <tbody className="divide-y divide-slate-100">
                  {itemsList.map((item, idx) => (
                    <tr key={idx}>
                      <td className="p-3 text-slate-800 font-medium">{item.name}</td>
                      <td className="p-3 text-right font-bold">{item.initialQty}</td>
                      <td className="p-3 text-right">R$ {(item.initialQty * item.unitValue).toLocaleString('pt-BR', { minimumFractionDigits: 2 })}</td>
                      <td className="p-3 text-center"><button onClick={() => handleRemoveItem(idx)} className="text-red-400 hover:text-red-600"><Trash2 size={16} /></button></td>
                    </tr>
                  ))}
                </tbody>
              </table>
            ) : <div className="p-8 text-center text-slate-400 flex flex-col items-center gap-2"><Search size={32} className="opacity-20" /><span>Adicione itens acima para listar aqui.</span></div>}
          </div>
        </div>
      </div>
    </div>
  );
};

export default Entry;
